mapper.update:
UPDATE notice
SET notice_title = #{noticeTitle}, notice_content = #{noticeContent}
WHERE notice_no = #{noticeNo}

UPDATE notice
SET status = 'N'
WHERE notice_no = #{noticeNo}

mapper.select:
SELECT file_no, origin_name, change_name, target_type, target_no
FROM files
WHERE target_type = 'NOTICE' AND target_no = #{noticeNo}
